const inputData = $input.item.json;
const body = inputData.body || inputData;
const query = inputData.query || {};

const method = String(inputData.method || inputData.httpMethod || '').toUpperCase();

// Webhook Verification (GET request from Meta)
const isVerificationRequest = 
  method === 'GET' &&
  query['hub.mode'] === 'subscribe' &&
  typeof query['hub.verify_token'] === 'string' &&
  query['hub.verify_token'].length > 0;

if (isVerificationRequest) {
  return [{
    json: {
      isVerification: true,
      isMessage: false,
      challenge: query['hub.challenge'] || '',
      verifyToken: query['hub.verify_token'] || ''
    }
  }];
}

// Process WhatsApp Message (POST request)
if (body.object === 'whatsapp_business_account' && body.entry) {
  const results = [];

  for (const entry of body.entry) {
    if (!entry.changes) continue;

    for (const change of entry.changes) {
      const value = change.value;

      if (value.messages && value.messages.length > 0) {
        for (const message of value.messages) {
          const contact = value.contacts?.find(c => c.wa_id === message.from) || {};

          let messageText = '';
          switch (message.type) {
            case 'text':
              messageText = message.text?.body || '';
              break;
            case 'button':
              // الرد على زر من قالب الرسالة
              messageText = message.button?.text || 'ضغط على زر';
              break;
            case 'interactive':
              // الرد على رسالة تفاعلية (أزرار أو قوائم)
              if (message.interactive?.type === 'button_reply') {
                messageText = message.interactive.button_reply?.title || 'رد على زر';
              } else if (message.interactive?.type === 'list_reply') {
                messageText = message.interactive.list_reply?.title || 'اختيار من القائمة';
              } else {
                messageText = message.interactive?.body?.text || '[رسالة تفاعلية]';
              }
              break;
            case 'image':
              messageText = message.image?.caption || '[صورة]';
              break;
            case 'video':
              messageText = message.video?.caption || '[فيديو]';
              break;
            case 'audio':
              messageText = '[رسالة صوتية]';
              break;
            case 'document':
              messageText = message.document?.filename || '[ملف]';
              break;
            case 'sticker':
              messageText = '[ملصق]';
              break;
            case 'location':
              messageText = '[موقع]';
              break;
            case 'contacts':
              messageText = '[جهة اتصال]';
              break;
            case 'reaction':
              messageText = message.reaction?.emoji || '[تفاعل]';
              break;
            default:
              messageText = '[' + message.type + ']';
          }

          const phoneNumber = message.from;
          const msgId = message.id.replace(/\//g, '_');

          results.push({
            json: {
              isVerification: false,
              isMessage: true,
              messageId: msgId,
              phoneNumber: phoneNumber,
              contactName: contact.profile?.name || phoneNumber,
              messageType: message.type,
              text: messageText,
              timestamp: parseInt(message.timestamp),
              timestampMs: Date.now()
            }
          });
        }
      }
    }
  }

  if (results.length > 0) return results;
}

return [{ json: { isVerification: false, isMessage: false, error: 'No valid data' } }];

const expectedToken = '4bZXa4hJ6whfqWf9JsyNjQpHzaBZOxZA1A81SBGH4ce90e2e';
const data = $input.item.json;

if (data.verifyToken === expectedToken) {
  return [{ json: { challenge: data.challenge, verified: true } }];
} else {
  return [{ json: { error: 'Invalid token', verified: false } }];
}

